#ifndef GEMM_N4096_K14336_KERNEL_H
#define GEMM_N4096_K14336_KERNEL_H

#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <stdint.h>

#ifdef __cplusplus
extern "C" {
#endif

// Computes C[M,4096] = A[M,14336] * B[4096,14336]^T
// A: row-major [M,K], K=14336
// B: row-major [N,K], N=4096, K=14336
// C: row-major [M,N], N=4096
void gemm_n4096_k14336_launch(const half* A,
                             const half* B,
                             half* C,
                             int M,
                             cudaStream_t stream);

#ifdef __cplusplus
}
#endif

#endif // GEMM_N4096_K14336_KERNEL_H

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <stdint.h>

#include <mma.h>

using namespace nvcuda;

static constexpr int N_CONST = 4096;
static constexpr int K_CONST = 14336;

static constexpr int WMMA_M = 16;
static constexpr int WMMA_N = 16;
static constexpr int WMMA_K = 16;

// 8 warps / block => 256 threads.
// Each warp computes 1x4 WMMA tiles => 16x64.
// Block computes 64x128 (4 warp_m * 16 = 64 rows, 2 warp_n * 64 = 128 cols).
static constexpr int WARPS_PER_BLOCK = 8;
static constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * 32;

static constexpr int BLOCK_M = 64;
static constexpr int BLOCK_N = 128;

__global__ __launch_bounds__(THREADS_PER_BLOCK, 2)
void gemm_n4096_k14336_wmma_kernel(const half* __restrict__ A,
                                  const half* __restrict__ B,
                                  half* __restrict__ C,
                                  int M) {
#if __CUDA_ARCH__ >= 700
  const int block_row = int(blockIdx.y) * BLOCK_M;
  const int block_col = int(blockIdx.x) * BLOCK_N;

  const int warp_id = int(threadIdx.x) >> 5;   // 0..7
  const int lane_id = int(threadIdx.x) & 31;

  // Warp layout: 4 warps along M, 2 along N
  const int warp_m = warp_id & 3;   // 0..3
  const int warp_n = warp_id >> 2;  // 0..1

  const int tile_row = block_row + warp_m * WMMA_M;
  const int tile_col_base = block_col + warp_n * (BLOCK_N / 2); // 0 or 64

  extern __shared__ __align__(16) unsigned char smem_raw[];
  half* shA = reinterpret_cast<half*>(smem_raw);                                 // [BLOCK_M,16]
  half* shB = shA + (BLOCK_M * WMMA_K);                                          // [16,BLOCK_N]
  float* shF = reinterpret_cast<float*>(shB + (WMMA_K * BLOCK_N));               // float scratch

  wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> acc[4];
#pragma unroll
  for (int j = 0; j < 4; ++j) wmma::fill_fragment(acc[j], 0.0f);

  wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, half, wmma::row_major> a_frag;
  // IMPORTANT: B is stored as row-major [N,K] but we compute B^T.
  // We stage shB as a row-major [K,N] tile, so we must load it as col_major
  // (so that the logical matrix for MMA is [K,N] with leading dimension BLOCK_N).
  wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, half, wmma::col_major> b_frag;

  for (int k0 = 0; k0 < K_CONST; k0 += WMMA_K) {
    // Load A tile [BLOCK_M,16] from global to shared.
    // Use half2 vectorization; pad out-of-range rows with 0.
    const int a_half2_elems = (BLOCK_M * WMMA_K) / 2;
    for (int idx = int(threadIdx.x); idx < a_half2_elems; idx += THREADS_PER_BLOCK) {
      const int elem = idx * 2;         // half index
      const int r = elem >> 4;          // /16
      const int c = elem & 15;          // %16 (even)
      const int gr = block_row + r;
      const int gc = k0 + c;

      half2 v2 = __float2half2_rn(0.0f);
      if (gr < M) {
        const half* ap = A + gr * K_CONST + gc;
        v2 = *reinterpret_cast<const half2*>(ap);
      }
      *reinterpret_cast<half2*>(shA + r * WMMA_K + c) = v2;
    }

    // Load B tile for this block: global B is [N,K] row-major.
    // We need shB as [K,N] so that it represents B^T for this k0-slab.
    // Read half2 from B[gn, k0+k] and scatter to shB[k, n].
    const int b_half2_elems = (BLOCK_N * WMMA_K) / 2;
    for (int idx = int(threadIdx.x); idx < b_half2_elems; idx += THREADS_PER_BLOCK) {
      const int elem = idx * 2;
      const int n = elem >> 4;  // 0..127
      const int k = elem & 15;  // even 0..15
      const int gn = block_col + n;   // always < 4096 due to exact tiling
      const int gk = k0 + k;

      half2 v2 = *reinterpret_cast<const half2*>(B + gn * K_CONST + gk);
      shB[(k + 0) * BLOCK_N + n] = __low2half(v2);
      shB[(k + 1) * BLOCK_N + n] = __high2half(v2);
    }

    __syncthreads();

    if (tile_row < M) {
      const half* a_ptr = shA + (warp_m * WMMA_M) * WMMA_K;
      wmma::load_matrix_sync(a_frag, a_ptr, WMMA_K);

#pragma unroll
      for (int j = 0; j < 4; ++j) {
        const int tile_col = tile_col_base + j * WMMA_N;
        const int col_off = tile_col - block_col; // 0..127
        const half* b_ptr = shB + col_off;        // points at shB[0, col_off]
        // b_frag is col_major: interprets shB as (K x N) with ld=BLOCK_N
        wmma::load_matrix_sync(b_frag, b_ptr, BLOCK_N);
        wmma::mma_sync(acc[j], a_frag, b_frag, acc[j]);
      }
    }

    __syncthreads();
  }

  // Store accumulator -> shared float -> global half
  if (tile_row < M) {
#pragma unroll
    for (int j = 0; j < 4; ++j) {
      const int tile_col = tile_col_base + j * WMMA_N;
      float* tile_out_f = shF + (warp_id * 4 + j) * (WMMA_M * WMMA_N);

      wmma::store_matrix_sync(tile_out_f, acc[j], WMMA_N, wmma::mem_row_major);

      for (int t = lane_id; t < WMMA_M * WMMA_N; t += 32) {
        const int rr = t / WMMA_N;
        const int cc = t - rr * WMMA_N;
        const int gr = tile_row + rr;
        const int gc = tile_col + cc;
        if (gr < M) {
          C[gr * N_CONST + gc] = __float2half_rn(tile_out_f[t]);
        }
      }
    }
  }
#else
  (void)A; (void)B; (void)C; (void)M;
#endif
}

void gemm_n4096_k14336_launch(const half* A, const half* B, half* C, int M, cudaStream_t stream) {
  dim3 block(THREADS_PER_BLOCK, 1, 1);
  dim3 grid((N_CONST + BLOCK_N - 1) / BLOCK_N, (M + BLOCK_M - 1) / BLOCK_M, 1);

  const size_t sh_half_bytes = (BLOCK_M * WMMA_K + WMMA_K * BLOCK_N) * sizeof(half);
  const size_t sh_float_bytes = (WARPS_PER_BLOCK * 4 * WMMA_M * WMMA_N) * sizeof(float);
  const size_t shmem_bytes = sh_half_bytes + sh_float_bytes;

  gemm_n4096_k14336_wmma_kernel<<<grid, block, shmem_bytes, stream>>>(A, B, C, M);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <cuda_runtime.h>
#include <cuda_fp16.h>

#include <sstream>
#include <stdexcept>
#include <string>

#include "kernel.h"

static void check_inputs(const torch::Tensor& A, const torch::Tensor& B) {
  if (!A.defined() || !B.defined()) throw std::invalid_argument("A and B must be defined");
  if (!A.device().is_cuda() || !B.device().is_cuda())
    throw std::invalid_argument("A and B must be CUDA tensors");
  if (A.dtype() != torch::kFloat16 || B.dtype() != torch::kFloat16)
    throw std::invalid_argument("A and B must be torch.float16");
  if (A.dim() != 2 || B.dim() != 2) throw std::invalid_argument("A and B must be 2D tensors");

  const auto M = A.size(0);
  const auto K = A.size(1);
  const auto N = B.size(0);
  const auto Kb = B.size(1);

  if (K != 14336) {
    std::ostringstream oss;
    oss << "A.size(1) must be 14336, got " << K;
    throw std::invalid_argument(oss.str());
  }
  if (N != 4096) {
    std::ostringstream oss;
    oss << "B.size(0) must be 4096, got " << N;
    throw std::invalid_argument(oss.str());
  }
  if (Kb != 14336) {
    std::ostringstream oss;
    oss << "B.size(1) must be 14336, got " << Kb;
    throw std::invalid_argument(oss.str());
  }
  if (M <= 0) throw std::invalid_argument("A.size(0)=M must be > 0");

  if (!A.is_contiguous()) throw std::invalid_argument("A must be contiguous (row-major)");
  if (!B.is_contiguous()) throw std::invalid_argument("B must be contiguous (row-major)");
}

torch::Tensor run(torch::Tensor A,
                  torch::Tensor B,
                  torch::optional<torch::Tensor> out = torch::nullopt) {
  check_inputs(A, B);

  const int64_t M64 = A.size(0);
  if (M64 > INT32_MAX) throw std::invalid_argument("M too large for int32 kernel");
  const int M = static_cast<int>(M64);

  torch::Tensor C;
  if (out.has_value() && out.value().defined()) {
    C = out.value();
    if (!C.device().is_cuda()) throw std::invalid_argument("out must be a CUDA tensor");
    if (C.dtype() != torch::kFloat16) throw std::invalid_argument("out must be torch.float16");
    if (C.dim() != 2 || C.size(0) != M || C.size(1) != 4096)
      throw std::invalid_argument("out must have shape [M, 4096]");
    if (!C.is_contiguous()) throw std::invalid_argument("out must be contiguous");
  } else {
    C = torch::empty({M, 4096}, torch::TensorOptions().dtype(torch::kFloat16).device(A.device()));
  }

  const half* A_ptr = reinterpret_cast<const half*>(A.data_ptr<at::Half>());
  const half* B_ptr = reinterpret_cast<const half*>(B.data_ptr<at::Half>());
  half* C_ptr = reinterpret_cast<half*>(C.data_ptr<at::Half>());

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();
  gemm_n4096_k14336_launch(A_ptr, B_ptr, C_ptr, M, stream);

  cudaError_t err = cudaGetLastError();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA launch error: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  return C;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "gemm_n4096_k14336: C = A @ B.T (CUDA, FP16, WMMA)");
}
